  1→import {getQueryParam} from '../../utils/url';
  2→import type {
  3→  ListingType,
  4→  EcommerceItem,
  5→  PromotionData,
  6→  GtmListingInstance,
  7→  ListingImpressionData
  8→} from './types';
  9→
 10→const MAX_IMPRESSION_ITEMS = 9;
 11→const IMPRESSION_RETRY_DELAY_MS = 1000;
 12→const MAX_IMPRESSION_RETRIES = 10;
 13→const VIEW_PROMOTION_THRESHOLD = 0.6;
 14→
 15→class GtmListing implements GtmListingInstance {
 16→  private publishedPromotionIds: string[] = [];
 17→  private impressionRetries = 0;
 18→
 19→  constructor() {
 20→    document.addEventListener('DOMContentLoaded', this.fireImpression);
 21→    document.addEventListener('DOMContentLoaded', this.viewCategoryEcomEvent);
 22→    $(document).on('click', '.pc-ProductCard-link', this.selectItemEcomEvent);
 23→    $(document).on('click', '.pc-CatCard-link', this.selectCategoryEcomEvent);
 24→  }
 25→
 26→  fireImpression = (): void => {
 27→    if ($('.pc-Styles').length && ProductCatalog.Styles?.cards().length > 0) {
 28→      this.listingImpression();
 29→    } else if (
 30→      $('.pc-Styles').length &&
 31→      this.impressionRetries < MAX_IMPRESSION_RETRIES
 32→    ) {
 33→      this.impressionRetries++;
 34→      setTimeout(this.fireImpression, IMPRESSION_RETRY_DELAY_MS);
 35→    }
 36→  };
 37→
 38→  private listingImpression(): void {
 39→    const list = this.getListingImpressionName();
 40→    const cards = ProductCatalog.Styles.cards()
 41→      .slice(0, MAX_IMPRESSION_ITEMS)
 42→      .toArray();
 43→
 44→    cards.forEach((card, index) => {
 45→      const $card = $(card);
 46→      const data = $card.find('.pc-ProductCard-dataLayer').data();
 47→
 48→      if (data) {
 49→        const impressionData = {
 50→          ...(data as ListingImpressionData),
 51→          position: index + 1,
 52→          list
 53→        };
 54→
 55→        ProductCatalog.gtmEvent(
 56→          'listingImpression',
 57→          'listingsImpression',
 58→          impressionData
 59→        );
 60→      }
 61→    });
 62→  }
 63→
 64→  private getListingImpressionName(): ListingType {
 65→    if (ProductCatalog.Styles.isSearchResults()) {
 66→      return 'Search Results';
 67→    }
 68→
 69→    if (ProductCatalog.Styles.isCustom()) {
 70→      return 'Listing Custom';
 71→    }
 72→
 73→    return 'Listing';
 74→  }
 75→
 76→  selectItemEcomEvent = (e: JQuery.ClickEvent): void => {
 77→    const $card = $(e.currentTarget).parents('.pc-ProductCard');
 78→    const data = $card.find('.pc-ProductCard-ecomDataLayer').data() as
 79→      | {items: EcommerceItem[]}
 80→      | undefined;
 81→
 82→    if (!data?.items?.[0]) {
 83→      return;
 84→    }
 85→
 86→    const [item] = data.items;
 87→    const cardIndex = $('.pc-ProductCard').index($card) + 1;
 88→
 89→    const enrichedItem: EcommerceItem = {
 90→      ...item,
 91→      index: cardIndex,
 92→      item_list_name: this.getListingImpressionName()
 93→    };
 94→
 95→    const $categoryMeta = $('meta[property=categoryinfo]');
 96→    const categoryId = $categoryMeta.prop('id') as string | undefined;
 97→    const ecommerce = {
 98→      item_list_id: categoryId ? parseInt(categoryId, 10) : Number.NaN,
 99→      item_list_name: $categoryMeta.attr('category_tree'),
100→      items: [enrichedItem]
101→    };
102→
103→    ProductCatalog.gtmEcomEvent('select_item', {
104→      search_term: getQueryParam('keyword'),
105→      ecommerce
106→    });
107→  };
108→
109→  selectCategoryEcomEvent = (e: JQuery.ClickEvent): void => {
110→    const $card = $(e.currentTarget).parents('.pc-CatCard');
111→    const data = $card.find('.pc-CatCard-ecomDataLayer').data() as
112→      | {promotion: PromotionData}
113→      | undefined;
114→
115→    if (!data?.promotion) {
116→      return;
117→    }
118→
119→    const {promotion} = data;
120→    const eventData = this.buildPromotionEventData(promotion);
121→
122→    ProductCatalog.gtmEcomEvent('select_promotion', eventData);
123→  };
124→
125→  viewCategoryEcomEvent = (): void => {
126→    const elements = document.querySelectorAll('.pc-CatCard');
127→
128→    const observer = new IntersectionObserver(
129→      (entries) => this.handleCategoryIntersection(entries),
130→      {threshold: VIEW_PROMOTION_THRESHOLD}
131→    );
132→
133→    elements.forEach((elem) => observer.observe(elem));
134→  };
135→
136→  private handleCategoryIntersection(
137→    entries: IntersectionObserverEntry[]
138→  ): void {
139→    entries.forEach((entry) => {
140→      if (!entry.isIntersecting) {
141→        return;
142→      }
143→
144→      const dataElement = entry.target.querySelector(
145→        '.pc-CatCard-ecomDataLayer'
146→      ) as HTMLElement | null;
147→      const dataSet = dataElement?.dataset;
148→
149→      if (!dataSet?.promotion) {
150→        return;
151→      }
152→
153→      const promotion = JSON.parse(dataSet.promotion) as PromotionData;
154→
155→      if (this.publishedPromotionIds.includes(promotion.promotion_id)) {
156→        return;
157→      }
158→
159→      this.publishedPromotionIds.push(promotion.promotion_id);
160→      const eventData = this.buildPromotionEventData(promotion);
161→      ProductCatalog.gtmEcomEvent('view_promotion', eventData);
162→    });
163→  }
164→
165→  private buildPromotionEventData(
166→    promotion: PromotionData
167→  ): Record<string, unknown> {
168→    return {
169→      ...promotion,
170→      items: promotion.items.map((item) => ({
171→        item_id: String(item.item_id),
172→        item_name: String(item.item_name)
173→      }))
174→    };
175→  }
176→}
177→
178→ProductCatalog.GtmListing = new GtmListing();
179→
180→export {GtmListing};
